import 'package:flutter_riverpod/flutter_riverpod.dart';
import 'package:riverpod/riverpod.dart' as riverpod;
import 'package:supabase_flutter/supabase_flutter.dart';

class PurchaseOrdersNotifier
    extends riverpod.Notifier<List<Map<String, dynamic>>> {
  @override
  List<Map<String, dynamic>> build() => <Map<String, dynamic>>[];

  void setOrders(List<Map<String, dynamic>> orders) {
    final sorted = [...orders]
      ..sort((a, b) {
        final aDate = DateTime.tryParse(a['created_at']?.toString() ?? '') ??
            DateTime.fromMillisecondsSinceEpoch(0);
        final bDate = DateTime.tryParse(b['created_at']?.toString() ?? '') ??
            DateTime.fromMillisecondsSinceEpoch(0);
        return bDate.compareTo(aDate);
      });
    state = sorted;
  }

  void addOrder(Map<String, dynamic> order) {
    final next = <Map<String, dynamic>>[order, ...state];
    setOrders(next);
  }

  void updateOrder(Map<String, dynamic> order) {
    final id = order['id'];
    final next = state
        .map((existing) => existing['id'] == id ? order : existing)
        .toList();
    setOrders(next);
  }

  void removeOrder(String id) {
    state = state.where((order) => order['id'] != id).toList();
  }
}

final purchaseOrdersProvider = NotifierProvider<PurchaseOrdersNotifier,
    List<Map<String, dynamic>>>(() => PurchaseOrdersNotifier());

class PurchaseOrdersRepository {
  const PurchaseOrdersRepository._();

  static const _baseSelect =
      'id,supplier_name,department,status,total,expected_date,notes,created_at,updated_at,'
      'supplier:suppliers(id,name),' // joined supplier reference
      'recorded_by_user:app_users(id,full_name,role)';

  static SupabaseClient get _client => Supabase.instance.client;

  static Future<List<Map<String, dynamic>>> listOrders() async {
    try {
      final response = await _client
          .from('purchase_orders')
          .select(_baseSelect)
          .order('created_at', ascending: false);
      return List<Map<String, dynamic>>.from(
        (response as List).map((row) => Map<String, dynamic>.from(row as Map)),
      );
    } catch (_) {
      return <Map<String, dynamic>>[];
    }
  }

  static Future<Map<String, dynamic>?> createOrder({
    required String supplierName,
    String? supplierId,
    required String status,
    required double total,
    String? department,
    String? notes,
    DateTime? expectedDate,
    String? recordedBy,
  }) async {
    try {
      final payload = {
        'supplier_name': supplierName,
        'supplier_id': supplierId,
        'status': status,
        'total': total,
        'department': department,
        'notes': notes,
        'expected_date': expectedDate?.toIso8601String(),
        'recorded_by': recordedBy,
      }..removeWhere((key, value) => value == null);

      final insert = await _client
          .from('purchase_orders')
          .insert(payload)
          .select(_baseSelect)
          .maybeSingle();
      if (insert == null) return null;
      return Map<String, dynamic>.from(insert as Map);
    } catch (_) {
      return null;
    }
  }

  static Future<Map<String, dynamic>?> updateStatus({
    required String id,
    required String status,
  }) async {
    try {
      final updated = await _client
          .from('purchase_orders')
          .update({'status': status})
          .eq('id', id)
          .select(_baseSelect)
          .maybeSingle();
      if (updated == null) return null;
      return Map<String, dynamic>.from(updated as Map);
    } catch (_) {
      return null;
    }
  }

  static Future<Map<String, dynamic>?> updateOrder({
    required String id,
    String? supplierName,
    String? supplierId,
    String? department,
    String? notes,
    DateTime? expectedDate,
    double? total,
  }) async {
    try {
      final payload = <String, dynamic>{}
        ..addAll({
          if (supplierName != null) 'supplier_name': supplierName,
          if (supplierId != null) 'supplier_id': supplierId,
          if (department != null) 'department': department,
          if (notes != null) 'notes': notes,
          if (expectedDate != null) 'expected_date': expectedDate.toIso8601String(),
          if (total != null) 'total': total,
        });

      final result = await _client
          .from('purchase_orders')
          .update(payload)
          .eq('id', id)
          .select(_baseSelect)
          .maybeSingle();
      if (result == null) return null;
      return Map<String, dynamic>.from(result as Map);
    } catch (_) {
      return null;
    }
  }

  static Future<bool> deleteOrder(String id) async {
    try {
      await _client.from('purchase_orders').delete().eq('id', id);
      return true;
    } catch (_) {
      return false;
    }
  }
}

Future<void> refreshPurchaseOrders(WidgetRef ref) async {
  final orders = await PurchaseOrdersRepository.listOrders();
  ref.read(purchaseOrdersProvider.notifier).setOrders(orders);
}

Future<bool> recordPurchaseOrder(
  WidgetRef ref, {
  required String supplierName,
  String? supplierId,
  required String status,
  required double total,
  String? department,
  String? notes,
  DateTime? expectedDate,
  String? recordedBy,
}) async {
  final order = await PurchaseOrdersRepository.createOrder(
    supplierName: supplierName,
    supplierId: supplierId,
    status: status,
    total: total,
    department: department,
    notes: notes,
    expectedDate: expectedDate,
    recordedBy: recordedBy,
  );
  if (order == null) return false;
  ref.read(purchaseOrdersProvider.notifier).addOrder(order);
  return true;
}

Future<bool> changePurchaseOrderStatus(
  WidgetRef ref, {
  required String id,
  required String status,
}) async {
  final order = await PurchaseOrdersRepository.updateStatus(
    id: id,
    status: status,
  );
  if (order == null) return false;
  ref.read(purchaseOrdersProvider.notifier).updateOrder(order);
  return true;
}

Future<bool> deletePurchaseOrder(
  WidgetRef ref, {
  required String id,
}) async {
  final ok = await PurchaseOrdersRepository.deleteOrder(id);
  if (ok) {
    ref.read(purchaseOrdersProvider.notifier).removeOrder(id);
  }
  return ok;
}
